local LDefenceWarBaseActor = LXImport(".LDefenceWarBaseActor")

local LDefenceWarMoveActor = LxClass("LDefenceWarMoveActor", LDefenceWarBaseActor)
----------------------------------------------------------------
-----------------------------------------------------------------
function LDefenceWarMoveActor:LDefenceWarMoveActor()
    self._stop = true
end

-- 销毁
function LDefenceWarMoveActor:Destroy()
end

-- 销毁
function LDefenceWarMoveActor:OnDestroy()

end

-- Update
function LDefenceWarMoveActor:Update(dt)
    if self._stop then
        return
    end
    local speed = self:GetSpeed()
    local trans = self:GetTransform()
    local pos = trans.localPosition
    pos.y = pos.y - speed * dt * 0.001
    if pos.y <= 0 then
        pos.y = 0
        self:StopMove()
        self:StartAttack()
    end
    trans.localPosition = pos
end

-- 开始移动
function LDefenceWarMoveActor:StartMove()
    self._stop = false

    local aniActor = self:GetObj():GetAniActor()
    aniActor:PlayRun()
end

-- 停止移动
function LDefenceWarMoveActor:StopMove()
    self._stop = true

    local aniActor = self:GetObj():GetAniActor()
    aniActor:PlayIdle()
end

-- 开始攻击
function LDefenceWarMoveActor:StartAttack()
    local atkActor = self:GetObj():GetAtkActor()
    atkActor:StartAtk()
end

-- 获取移动速度
function LDefenceWarMoveActor:GetSpeed()
    local data = self:GetData()
    return data:GetMoveSpeed()
end

return LDefenceWarMoveActor
